elements.onScroll:
function(event, data, view, point, width, height) {var scope = this;
handleScroll(event, data, view, point, width, height);

function handleScroll(event, data, view, point, width, height) {
    var scrollInfo = scope.__cunstomScrollInfo;
    if(!scrollInfo){
        return
    }
    var scrollSpeed = 1;
    var tyName, txName;
    tyName = getBindingInfo(scope, 'translateY', data);
    txName = getBindingInfo(scope, 'translateX', data);
    if (!scrollInfo) return;
    var { scrollBarX, scrollBarY, minX, minY } = scrollInfo;
    var deltaX = (event.wheelDeltaX || -event.deltaX || 0) / 40 * 5 * scrollSpeed;
    var deltaY = (event.wheelDeltaY || -event.deltaY || 0) / 40 * 5 * scrollSpeed;
    var deal = false;
    if (scrollBarY && tyName && deltaY) {
        var ty = (data.a(tyName) || 0) + deltaY;
        ty = Math.min(0, ty);
        ty = Math.max(minY, ty);
        data.a(tyName, ty);
        deal = true;
    }
    if (scrollBarX && txName && deltaX) {
        var tx = (data.a(txName) || 0) + deltaX;
        tx = Math.min(0, tx);
        tx = Math.max(minX, tx);
        data.a(txName, tx);
        deal = true;
    }
    if (!deal && scrollBarX && !scrollBarY && txName && deltaY) {
        var tx = (data.a(txName) || 0) + deltaY;
        tx = Math.min(0, tx);
        tx = Math.max(minX, tx);
        data.a(txName, tx);
    }
    data.iv();
}

function getBindingInfo(comp, attributeName, data, view) {
    if (!comp) {
        return;
    }
    var attr = comp[attributeName];
    const prefix = data.getCurrentPrefix();
    if (attr && attr.func) {
        if (typeof attr.func === 'string') {
            var arr = attr.func.split('@'),
                [accessType, name] = arr;
            return (prefix || '') + name;
        }
    }
    return null;
}}
